import React, { useEffect, useState } from "react";

const UploadBills = ({ employee }) => {
  const [files, setFiles] = useState([]);
  const [bills, setBills] = useState([]);

  useEffect(() => {
    if (employee?.empId || employee?.empld) {
      loadBills();
    }
  }, [employee]);

  const loadBills = async () => {
    try {
      const empId = employee.empId || employee.empld;
      const res = await fetch(
        `https://prasa-app-yde3.onrender.com/bills?empId=${encodeURIComponent(
          empId
        )}`
      );
      const data = await res.json();
      setBills(Array.isArray(data) ? data : []);
    } catch (err) {
      console.error(err);
      setBills([]);
    }
  };

  const uploadBills = async () => {
    if (!files.length) {
      alert("Select at least one file");
      return;
    }

    const empId = employee.empId || employee.empld;
    const form = new FormData();
    form.append("empId", empId);
    for (let file of files) {
      form.append("bills", file);
    }

    await fetch("https://prasa-app-yde3.onrender.com/upload-bills", {
      method: "POST",
      body: form,
    });

    alert("Bills uploaded!");
    loadBills();
  };

  const deleteBill = async (id) => {
    await fetch(
      `https://prasa-app-yde3.onrender.com/delete-bill/${id}`,
      { method: "DELETE" }
    );
    loadBills();
  };

  const downloadReport = () => {
    alert("Bills Monthly Report download coming soon 🔥");
  };

  return (
    <div style={pageWrapper}>
      <div style={card}>
        {/* Header */}
        <div style={cardHeader}>
          <button
            style={backButton}
            onClick={() => window.history.back()}
          >
            ←
          </button>
          <h2 style={titleText}>Bills Upload History</h2>
        </div>

        <p style={employeeText}>
          Employee: {employee.empName || employee.name} •{" "}
          {employee.empId || employee.empld}
        </p>

        {/* Upload section */}
        <div style={uploadRow}>
          <input
            type="file"
            multiple
            onChange={(e) => setFiles(Array.from(e.target.files))}
            style={fileInput}
          />
          <button style={uploadButton} onClick={uploadBills}>
            Upload Bills
          </button>
        </div>

        {/* Table */}
        <div style={tableWrapper}>
          <table style={table}>
            <thead>
              <tr>
                <th>Date</th>
                <th>File Name</th>
                <th>Preview</th>
                <th>Delete</th>
              </tr>
            </thead>
            <tbody>
              {bills.length > 0 ? (
                bills.map((b) => (
                  <tr key={b.id}>
                    <td>{b.uploaded_at?.substring(0, 10)}</td>
                    <td>{b.file_name}</td>
                    <td>
                      <a
                        href={b.file_path}
                        target="_blank"
                        rel="noreferrer"
                      >
                        View
                      </a>
                    </td>
                    <td>
                      <button
                        style={deleteButton}
                        onClick={() => deleteBill(b.id)}
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="4" style={noDataText}>
                    No bills uploaded yet
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* Download Monthly Bills report */}
        <div style={downloadRow}>
          <button style={downloadButton} onClick={downloadReport}>
            📄 Download Monthly Bills Report
          </button>
        </div>
      </div>
    </div>
  );
};

export default UploadBills;

/* ---------- STYLES ---------- */

const green = "#0F9D58";

const pageWrapper = {
  minHeight: "100vh",
  background: "#EAF8F0",
  padding: "20px",
};

const card = {
  background: "#ffffff",
  borderRadius: "16px",
  padding: "20px 24px",
  boxShadow: "0 4px 20px rgba(0,0,0,0.06)",
};

const cardHeader = {
  display: "flex",
  alignItems: "center",
  gap: "10px",
};

const backButton = {
  border: "none",
  background: "#ffffff",
  borderRadius: "999px",
  width: "36px",
  height: "36px",
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  fontSize: "20px",
  color: green,
  boxShadow: "0 2px 6px rgba(0,0,0,0.15)",
  cursor: "pointer",
};

const titleText = {
  margin: 0,
  fontSize: "22px",
  fontWeight: 600,
  color: green,
};

const employeeText = {
  marginTop: "6px",
  marginBottom: "14px",
  color: "#555",
  fontSize: "14px",
};

const uploadRow = {
  display: "flex",
  gap: "12px",
  alignItems: "center",
  background: "#F3FBF6",
  padding: "12px 14px",
  borderRadius: "12px",
  marginBottom: "16px",
};

const fileInput = {
  flex: 1,
};

const uploadButton = {
  background: green,
  color: "#fff",
  border: "none",
  borderRadius: "10px",
  padding: "9px 16px",
  cursor: "pointer",
  fontSize: "14px",
};

const tableWrapper = {
  marginTop: "10px",
  overflowX: "auto",
};

const table = {
  width: "100%",
  borderCollapse: "collapse",
};

const noDataText = {
  textAlign: "center",
  padding: "18px 0",
  color: "#777",
};

const deleteButton = {
  background: "#E53935",
  color: "#fff",
  border: "none",
  borderRadius: "8px",
  padding: "6px 10px",
  cursor: "pointer",
  fontSize: "13px",
};

const downloadRow = {
  marginTop: "16px",
  textAlign: "left",
};

const downloadButton = {
  background: green,
  color: "#fff",
  border: "none",
  borderRadius: "10px",
  padding: "10px 18px",
  fontSize: "15px",
  fontWeight: 600,
  cursor: "pointer",
};
